+    assert!(prioritized[0].1 >= prioritized[1].1);
+    assert!(prioritized[1].1 >= prioritized[2].1);
+    // id3 was re-accessed most recently after last decay => highest EWMA
+    assert_eq!(prioritized[0].0, id3);
