+    E2eLogEntry::new(
+        "info",
+        test_name,
+        "fcp-e2e",
+        phase,
+        "taint-approval-e2e",
+        result,
+        0,
+        AssertionsSummary::new(passed, failed),
+        context,
+    )
+}
